'use client'
import { cn, createMachine, useMachine, useSignals } from '@cascivo/core'
import type { ButtonHTMLAttributes } from 'react'
import styles from './toggle.module.css'

export interface ToggleProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, 'onChange'> {
  checked?: boolean
  defaultChecked?: boolean
  onChange?: (checked: boolean) => void
  /**
   * Renders a **visible** text label beside the switch that also becomes its
   * accessible name. When a visible heading already labels the control, omit
   * `label` (it would duplicate that text) and pass `aria-label` instead —
   * `aria-label` is forwarded to the underlying button.
   */
  label?: string
  size?: 'sm' | 'md'
}

export function Toggle({
  checked,
  defaultChecked = false,
  onChange,
  label,
  size = 'md',
  className,
  disabled,
  ...props
}: ToggleProps) {
  useSignals()
  const machine = createMachine({
    initial: defaultChecked ? ('on' as const) : ('off' as const),
    states: {
      off: { on: { TOGGLE: 'on' } },
      on: { on: { TOGGLE: 'off' } },
    },
  })
  const [state, send] = useMachine(machine)

  const isControlled = checked !== undefined
  const isOn = isControlled ? checked : state.value === 'on'

  const handleClick = () => {
    if (!isControlled) send('TOGGLE')
    onChange?.(!isOn)
  }

  return (
    <button
      type="button"
      role="switch"
      aria-checked={isOn}
      data-state={isOn ? 'on' : 'off'}
      data-size={size}
      disabled={disabled}
      className={cn(styles['toggle'], className)}
      onClick={handleClick}
      {...props}
    >
      <span className={styles['track']} aria-hidden="true">
        <span className={styles['thumb']} />
      </span>
      {label && <span className={styles['label']}>{label}</span>}
    </button>
  )
}

@layer cascivo.component {
  .toggle {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    padding: 0;
    background: none;
    border: none;
    font-family: var(--cascivo-font-sans);
    cursor: pointer;

    &[data-size='sm'] {
      --_track-w: 1.75rem;
      --_track-h: 1rem;
      --_thumb: 0.75rem;
    }
    &[data-size='md'] {
      --_track-w: 2.25rem;
      --_track-h: 1.25rem;
      --_thumb: 1rem;
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    &:focus-visible {
      outline: none;
    }
  }

  .track {
    display: inline-flex;
    align-items: center;
    flex-shrink: 0;
    inline-size: var(--_track-w);
    block-size: var(--_track-h);
    padding: 2px;
    border-radius: var(--cascivo-radius-full);
    background-color: var(--cascivo-color-border-strong);
    transition: background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    .toggle[data-state='on'] & {
      background-color: var(--cascivo-color-accent);
    }

    .toggle:focus-visible & {
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .thumb {
    inline-size: var(--_thumb);
    block-size: var(--_thumb);
    border-radius: var(--cascivo-radius-full);
    background-color: var(--cascivo-color-surface);
    box-shadow: var(--cascivo-shadow-sm);
    transition: translate var(--cascivo-duration-150) var(--cascivo-ease-out);

    .toggle[data-state='on'] & {
      translate: calc(var(--_track-w) - var(--_thumb) - 4px) 0;
    }
  }

  .label {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  /* Coarse-pointer touch targets — raise minimum to 44px, desktop density unchanged */
  @media (pointer: coarse) {
    .toggle {
      min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
    }
  }
}

@media (forced-colors: active) {
  .track {
    border: 1px solid ButtonText;
  }

  .toggle[data-state='on'] .track {
    border-color: Highlight;
    background-color: Highlight;
  }

  .toggle:focus-visible .track {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
